+fn prepare_output_path(path: &Path) -> Result<(), String> {
+    if let Some(parent) = path.parent() {
+        if !parent.as_os_str().is_empty() {
+            fs::create_dir_all(parent).map_err(|error| {
+                format!(
+                    "failed to create output directory {}: {error}",
+                    parent.display()
+                )
+            })?;
+        }
+    }
+    Ok(())
+}
